      Subroutine setSY(Nx,Nz,PP11,PP22,PP31,     &            PP33,PP51,PS11,PS51,PS22,PS31,SS11,     &            SS51,SS22,Y,SY)      Implicit    none      Integer     Nx,Nz,ix,iz      Complex*16  Y(Nx,9,Nz),SY(Nx,9,Nz)      Complex*16  PP11(Nx,Nz),PP22(Nx,Nz),PS31(Nx,Nz)      Complex*16  PP31(Nx,Nz),PP33(Nx,Nz),PP51(Nx,Nz)      Complex*16  PS11(Nx,Nz),PS51(Nx,Nz),PS22(Nx,Nz)      Complex*16  SS11(Nx,Nz),SS51(Nx,Nz),SS22(Nx,Nz)      Complex*16  P1,P2,P3,P4,P5,S1,S2,S4,S5      Do iz=1,Nz	  Do ix=1,Nx		  P1=Y(ix,1,iz)		  P2=Y(ix,2,iz)		  P3=Y(ix,3,iz)		  P4=Y(ix,4,iz)		  P5=Y(ix,5,iz)		  S1=Y(ix,6,iz)		  S2=Y(ix,7,iz)		  S4=Y(ix,8,iz)		  S5=Y(ix,9,iz)		  	      SY(ix,1,iz)=P5*PP51(ix,iz)+P3*PP31(ix,iz)+     &          P1*PP11(ix,iz)-PS51(ix,iz)*S5+PS11(ix,iz)*S1		  SY(ix,2,iz)=P2*PP22(ix,iz)+PS22(ix,iz)*S2		  SY(ix,3,iz)=P5*PP31(ix,iz)+P1*PP31(ix,iz)+     &          P3*PP33(ix,iz)+PS31(ix,iz)*(S1-S5)		  SY(ix,4,iz)=P4*PP22(ix,iz)-PS22(ix,iz)*S4		  SY(ix,5,iz)=P1*PP51(ix,iz)+P3*PP31(ix,iz)+     &          P5*PP11(ix,iz)-PS11(ix,iz)*S5+PS51(ix,iz)*S1		  SY(ix,6,iz)=-P5*PS51(ix,iz)-P3*PS31(ix,iz)-     &          P1*PS11(ix,iz)+S5*SS51(ix,iz)+S1*SS11(ix,iz)		  SY(ix,7,iz)=-P2*PS22(ix,iz)+S2*SS22(ix,iz)		  SY(ix,8,iz)=P4*PS22(ix,iz)+S4*SS22(ix,iz)		  SY(ix,9,iz)=P1*PS51(ix,iz)+P3*PS31(ix,iz)+     &          P5*PS11(ix,iz)+S1*SS51(ix,iz)+S5*SS11(ix,iz)	  Enddo	  Enddo      return      end      SUBROUTINE setPfSY(Nl,Nlm1,Nk,Nx,Nz,jskip,     &           R11,R21,R22,S11,S12,S21,S22,U11,U21,U22,     &           ea,eb,PD,SD,PU,SU,sigP,sigS,P1,P2,Q1,Q2,PC,SY,PSY)	*     set X=Pf*SY where Pf is the forward propagator in the actual medium      Implicit none      INTEGER     Nl,Nlm1,Nk,jskip,Nx,Nz      complex*16  SY(Nx,9,Nz),PSY(Nx,9,Nz)	        complex*16  PC(Nk,9,Nz)      Complex*16  U11(Nk,0:Nlm1)      Complex*16  U21(Nk,0:Nlm1),U22(Nk,0:Nlm1)      Complex*16  R11(Nk,Nl),R21(Nk,Nl),R22(Nk,Nl)      Complex*16  S11(Nk,Nlm1),S12(Nk,Nlm1)      Complex*16  S21(Nk,Nlm1),S22(Nk,Nlm1)      Complex*16  P1(Nk,Nl),P2(Nk,Nl),Q1(Nk,Nl),Q2(Nk,Nl)      Complex*16  ea(Nk,1:Nl),eb(Nk,1:Nl)      Complex*16  PD(Nk),SD(Nk),PU(Nk),SU(Nk)      Complex*16  sigP(Nk),sigS(Nk)*****************************************************************     LOCAL variables******************************************************************      type*,'entered setPSY'      call UpSweep(Nk,Nl,Nlm1,Nx,Nz,jskip,PC,SY,     &           R11,R21,R22,S11,S12,S21,S22,U11,U21,U22,     &           SigP,SigS,PD,SD,PU,SU,P1,P2,Q1,Q2)	       call DownSweep(Nk,NL,Nlm1,Nx,Nz,jskip,R11,R21,R22,     &     S11,S12,S21,S22,PD,SD,PU,SU,SigP,SigS,PC,P1,P2,Q1,Q2,PSY) 	 	  If(Nx.gt.1)then	    call LRsweep(Nk,Nz,Nx,PC,SY,PSY,PU,SU,PD,SD,Ea,Eb)      Endif      RETURN      END      Subroutine UpSweep(Nk,Nl,Nlm1,Nx,Nz,jskip,PC,SY,     &           R11,R21,R22,S11,S12,S21,S22,U11,U21,U22,     &           SigP,SigS,PD,SD,PU,SU,P1,P2,Q1,Q2)	       Implicit    None      Integer     NL,Nlm1,Nx,Nz,jskip,Nk      complex*16  SY(Nx,9,Nz)	        complex*16  PC(Nk,9,Nz)       Complex*16  U11(Nk,0:Nlm1)      Complex*16  U21(Nk,0:Nlm1),U22(Nk,0:Nlm1)      Complex*16  R11(Nk,Nl),R21(Nk,Nl),R22(Nk,Nl)      Complex*16  S11(Nk,Nlm1),S12(Nk,Nlm1)      Complex*16  S21(Nk,Nlm1),S22(Nk,Nlm1)      Complex*16  P1(Nk,Nl),P2(Nk,Nl),Q1(Nk,Nl),Q2(Nk,Nl)      Complex*16  PD(Nk),SD(Nk),PU(Nk),SU(Nk)      Complex*16  sigP(Nk),sigS(Nk)	        Integer     mm(9),ik,il,ilm1,ilp1,m,j,ix      Real*8      signi      Complex*16  C0             C0=(0.D0,0.D0)      mm(1)=5      mm(2)=4      mm(3)=3      mm(4)=2      mm(5)=1      mm(6)=9      mm(7)=8      mm(8)=7      mm(9)=6      Do ik=1,Nk        P1(ik,Nl)=C0        P2(ik,Nl)=C0      Enddo	        DO 99998 il=NL,1,-1        ilm1=il-1	  ilp1=il+1	  Do ik=1,Nk          PD(ik)=C0	  PU(ik)=C0	  SD(ik)=C0	  SU(ik)=C0	  Enddo	  Do 99996 m=1,5	  Do ik=1,Nk	    sigP(ik)=C0	   Enddo          j=1	  Do ix=1,Nx	    sigP(j)=SY(ix,m,il)	    j=j+jskip	  Enddo	  signi=-1.0	  call FFT(sigP,Nk,signi) !x->k	  Do ik=1,Nk	            PU(ik)=PU(ik)+PC(ik,m,il)*sigP(ik)          PD(ik)=PD(ik)+PC(ik,mm(m),il)*sigP(ik)	  Enddo99996   Continue			  Do 99997 m=6,9	  Do ik=1,Nk	    sigS(ik)=C0	  Enddo          j=1	  Do ix=1,Nx	    sigS(j)=SY(ix,m,il)	    j=j+jskip	  Enddo	  signi=-1.0	  call FFT(sigS,Nk,signi) !x->k	  Do ik=1,Nk	              SU(ik)=SU(ik)+PC(ik,m,il)*sigS(ik)            SD(ik)=SD(ik)+PC(ik,mm(m),il)*sigS(ik)	  Enddo99997    Continue		        DO ik=1,Nk*         P(il)=P(il)+R(il)*D(il)          P1(ik,il)=P1(ik,il)+R11(ik,il)*PD(ik)-R21(ik,il)*SD(ik)          P2(ik,il)=P2(ik,il)+R21(ik,il)*PD(ik)+R22(ik,il)*SD(ik)        Enddo        if(il.ne.nl)then          DO ik=1,Nk*           Q(il)=Q(il)+S(il)*D(il)            Q1(ik,ilp1)=Q1(ik,ilp1)+S11(ik,il)*PD(ik)+S12(ik,il)*SD(ik)            Q2(ik,ilp1)=Q2(ik,ilp1)+S21(ik,il)*PD(ik)+S22(ik,il)*SD(ik)          Enddo        endif***************************************************************************************************************************************************       U=(1+dtu)*P        DO ik=1,Nk*         PU=(PU+P1) & SU=(SU+P2)          PU(ik)=PU(ik)+P1(ik,il)          SU(ik)=SU(ik)+P2(ik,il)        Enddo**************************************************************************************************************************************************		        DO ik=1,Nk*         Q(il)=U(ilm1)*U          Q1(ik,il)=U11(ik,ilm1)*PU(ik)-U21(ik,ilm1)*SU(ik)          Q2(ik,il)=U21(ik,ilm1)*PU(ik)+U22(ik,ilm1)*SU(ik)        Enddo			  if(il.ne.1) then          DO ik=1,Nk*           P(ilm1)=T(ilm1)*U            P1(ik,ilm1)=S11(ik,ilm1)*PU(ik)-S21(ik,ilm1)*SU(ik)            P2(ik,ilm1)=-S12(ik,ilm1)*PU(ik)+S22(ik,ilm1)*SU(ik)          Enddo	  endif		99998 continue      return      end      Subroutine DownSweep(Nk,NL,Nlm1,Nx,Nz,jskip,R11,R21,R22,     & S11,S12,S21,S22,PD,SD,PU,SU,SigP,SigS,PC,P1,P2,Q1,Q2,PSY)      Implicit   None      Integer     Nk,NL,Nlm1,Nx,Nz,jskip      Complex*16  R11(Nk,1:Nl)      Complex*16  R21(Nk,1:Nl),R22(Nk,1:Nl)      Complex*16  S11(Nk,1:Nlm1),S12(Nk,1:Nlm1)      Complex*16  S21(Nk,1:Nlm1),S22(Nk,1:Nlm1)      Complex*16  P1(Nk,1:Nl),P2(Nk,1:Nl)      Complex*16  Q1(Nk,1:Nl),Q2(Nk,1:Nl)      Complex*16  PSY(Nx,9,Nz)      complex*16  PC(Nk,9,Nz)      Complex*16  PD(Nk),SD(Nk),PU(Nk),SU(Nk)      Complex*16  sigP(Nk),sigS(Nk)      Integer     mm(9),il,ilm1,ik,m,j,ix      Real*8      signi	  	  Complex*16  tp,ts,C0         C0=(0.0,0.0)      mm(1)=5      mm(2)=4      mm(3)=3      mm(4)=2      mm(5)=1      mm(6)=9      mm(7)=8      mm(8)=7      mm(9)=6	        DO 99998 IL=1,Nl	ilm1=il-1        if(il.ne.1)then***************************************************************************************************************************************************     D=(1+td)*D	  Do ik=1,Nk	    tp=Q1(ik,il)+S11(ik,ilm1)*PD(ik)+S12(ik,ilm1)*SD(ik)	    ts=Q2(ik,il)+S21(ik,ilm1)*PD(ik)+S22(ik,ilm1)*SD(ik)            PD(ik)=tp	    SD(ik)=ts	  Enddo**************************************************************************************************************************************************        else	  Do ik=1,Nk            PD(ik)=Q1(ik,il)	    SD(ik)=Q2(ik,il)	  Enddo        endif	Do ik=1,Nk	            PU(ik)=P1(ik,il)+R11(ik,il)*PD(ik)-R21(ik,il)*SD(ik)          SU(ik)=P2(ik,il)+R21(ik,il)*PD(ik)+R22(ik,il)*SD(ik)	Enddo        Do 99996 m=1,5	  Do ik=1,Nk            SigP(ik)=PC(ik,m,il)*PD(ik)+PC(ik,mm(m),il)*PU(ik)	  Enddo	  signi=1.0	  call FFT(SigP,Nk,signi) !k->x	  j=1	  Do ix=1,Nx	              PSY(ix,m,il)=SigP(j)	    j=j+jskip	  Enddo99996	continue        Do 99997 m=6,9	  Do ik=1,Nk            SigS(ik)=PC(ik,m,il)*SD(ik)+PC(ik,mm(m),il)*SU(ik)	  Enddo	  signi=1.0	  call FFT(SigS,Nk,signi) !k->x	  j=1	  Do ix=1,Nx	              PSY(ix,m,il)=SigS(j)	    j=j+jskip	  Enddo99997	continue99998 continue      return      end      subroutine setTd(il,Nk,Nx,jskip,SY,Y,PC,sigP,sigS,     &          PP11,PP22,PS31,PP31,PP33,PP51,PS11,PS51,PS22,     &          SS11,SS51,SS22,PD,SD,tdp,tds)*     tD=dtd*D	  Implicit none      Integer     Nk,il,Nx,jskip      Complex*16  PD(Nk),SD(Nk),tdp(Nk),tds(Nk)      Complex*16  SY(Nx,9),Y(Nx,9)      complex*16  PC(Nk,9,*)      Complex*16  sigP(Nk),sigS(Nk)      Complex*16  PP11(Nx,*),PP22(Nx,*),PS31(Nx,*)      Complex*16  PP31(Nx,*),PP33(Nx,*),PP51(Nx,*)      Complex*16  PS11(Nx,*),PS51(Nx,*),PS22(Nx,*)      Complex*16  SS11(Nx,*),SS51(Nx,*),SS22(Nx,*)      Integer     mm(9),ilm1,ik,m,j,ix      Complex*16  P1,P2,P3,P4,P5,S1,S2,S4,S5      Real*8      signi	  	  Complex*16  C0      C0=(0.0,0.0)      mm(1)=5      mm(2)=4      mm(3)=3      mm(4)=2      mm(5)=1      mm(6)=9      mm(7)=8      mm(8)=7      mm(9)=6        Do 99996 m=1,5	  Do ik=1,Nk            SigP(ik)=PC(ik,m,il)*PD(ik)	  Enddo	  signi=1.0	  call FFT(SigP,Nk,signi) !k->x	  j=1	  Do ix=1,Nx	              Y(ix,m)=SigP(j)	    j=j+jskip	  Enddo99996	continue        Do 99997 m=6,9	  Do ik=1,Nk            SigS(ik)=PC(ik,m,il)*SD(ik)	  Enddo	  signi=1.0	  call FFT(SigS,Nk,signi) !k->x	  j=1	  Do ix=1,Nx	              Y(ix,m)=SigS(j)	    j=j+jskip	  Enddo99997	continue99998 continue	  Do ix=1,Nx		  P1=Y(ix,1)		  P2=Y(ix,2)		  P3=Y(ix,3)		  P4=Y(ix,4)		  P5=Y(ix,5)		  S1=Y(ix,6)		  S2=Y(ix,7)		  S4=Y(ix,8)		  S5=Y(ix,9)		  	      SY(ix,1)=P5*PP51(ix,il)+P3*PP31(ix,il)+     &          P1*PP11(ix,il)-PS51(ix,il)*S5+PS11(ix,il)*S1		  SY(ix,2)=P2*PP22(ix,il)+PS22(ix,il)*S2		  SY(ix,3)=P5*PP31(ix,il)+P1*PP31(ix,il)+     &          P3*PP33(ix,il)+PS31(ix,il)*(S1-S5)		  SY(ix,4)=P4*PP22(ix,il)-PS22(ix,il)*S4		  SY(ix,5)=P1*PP51(ix,il)+P3*PP31(ix,il)+     &          P5*PP11(ix,il)-PS11(ix,il)*S5+PS51(ix,il)*S1		  SY(ix,6)=-P5*PS51(ix,il)-P3*PS31(ix,il)-     &          P1*PS11(ix,il)+S5*SS51(ix,il)+S1*SS11(ix,il)		  SY(ix,7)=-P2*PS22(ix,il)+S2*SS22(ix,il)		  SY(ix,8)=P4*PS22(ix,il)+S4*SS22(ix,il)		  SY(ix,9)=P1*PS51(ix,il)+P3*PS31(ix,il)+     &          P5*PS11(ix,il)+S1*SS51(ix,il)+S5*SS11(ix,il)	  Enddo	  Do ik=1,Nk          tdp(ik)=C0	      tds(ik)=C0	  Enddo	  Do 99992 m=1,5	  Do ik=1,Nk	    sigP(ik)=C0	   Enddo          j=1	  Do ix=1,Nx	    sigP(j)=SY(ix,m)	    j=j+jskip	  Enddo	  signi=-1.0	  call FFT(sigP,Nk,signi) !x->k	  Do ik=1,Nk	            tdp(ik)=tdp(ik)+PC(ik,mm(m),il)*sigP(ik)	  Enddo99992   Continue			  Do 99993 m=6,9	  Do ik=1,Nk	    sigS(ik)=C0	  Enddo          j=1	  Do ix=1,Nx	    sigS(j)=SY(ix,m)	    j=j+jskip	  Enddo	  signi=-1.0	  call FFT(sigS,Nk,signi) !x->k	  Do ik=1,Nk	              tds(ik)=tds(ik)+PC(ik,mm(m),il)*sigS(ik)	  Enddo99993    Continue	  	  return	  end      subroutine setTu(il,Nk,Nx,jskip,SY,Y,PC,sigP,sigS,     &          PP11,PP22,PS31,PP31,PP33,PP51,PS11,PS51,PS22,     &          SS11,SS51,SS22,PU,SU,tup,tus)*     tU=dtu*U	  Implicit none      Integer     Nk,il,Nx,jskip      Complex*16  PU(Nk),SU(Nk),tup(Nk),tus(Nk)      Complex*16  SY(Nx,9),Y(Nx,9)      complex*16  PC(Nk,9,*)      Complex*16  sigP(Nk),sigS(Nk)      Complex*16  PP11(Nx,*),PP22(Nx,*),PS31(Nx,*)      Complex*16  PP31(Nx,*),PP33(Nx,*),PP51(Nx,*)      Complex*16  PS11(Nx,*),PS51(Nx,*),PS22(Nx,*)      Complex*16  SS11(Nx,*),SS51(Nx,*),SS22(Nx,*)      Integer     mm(9),ilm1,ik,m,j,ix      Complex*16  P1,P2,P3,P4,P5,S1,S2,S4,S5      Real*8      signi	  	  Complex*16  C0      C0=(0.0,0.0)      mm(1)=5      mm(2)=4      mm(3)=3      mm(4)=2      mm(5)=1      mm(6)=9      mm(7)=8      mm(8)=7      mm(9)=6        Do 99996 m=1,5	  Do ik=1,Nk            SigP(ik)=PC(ik,mm(m),il)*PU(ik)	  Enddo	  signi=1.0	  call FFT(SigP,Nk,signi) !k->x	  j=1	  Do ix=1,Nx	              Y(ix,m)=SigP(j)	    j=j+jskip	  Enddo99996	continue        Do 99997 m=6,9	  Do ik=1,Nk            SigS(ik)=PC(ik,mm(m),il)*SU(ik)	  Enddo	  signi=1.0	  call FFT(SigS,Nk,signi) !k->x	  j=1	  Do ix=1,Nx	              Y(ix,m)=SigS(j)	    j=j+jskip	  Enddo99997	continue99998 continue	  Do ix=1,Nx		  P1=Y(ix,1)		  P2=Y(ix,2)		  P3=Y(ix,3)		  P4=Y(ix,4)		  P5=Y(ix,5)		  S1=Y(ix,6)		  S2=Y(ix,7)		  S4=Y(ix,8)		  S5=Y(ix,9)		  	      SY(ix,1)=P5*PP51(ix,il)+P3*PP31(ix,il)+     &          P1*PP11(ix,il)-PS51(ix,il)*S5+PS11(ix,il)*S1		  SY(ix,2)=P2*PP22(ix,il)+PS22(ix,il)*S2		  SY(ix,3)=P5*PP31(ix,il)+P1*PP31(ix,il)+     &          P3*PP33(ix,il)+PS31(ix,il)*(S1-S5)		  SY(ix,4)=P4*PP22(ix,il)-PS22(ix,il)*S4		  SY(ix,5)=P1*PP51(ix,il)+P3*PP31(ix,il)+     &          P5*PP11(ix,il)-PS11(ix,il)*S5+PS51(ix,il)*S1		  SY(ix,6)=-P5*PS51(ix,il)-P3*PS31(ix,il)-     &          P1*PS11(ix,il)+S5*SS51(ix,il)+S1*SS11(ix,il)		  SY(ix,7)=-P2*PS22(ix,il)+S2*SS22(ix,il)		  SY(ix,8)=P4*PS22(ix,il)+S4*SS22(ix,il)		  SY(ix,9)=P1*PS51(ix,il)+P3*PS31(ix,il)+     &          P5*PS11(ix,il)+S1*SS51(ix,il)+S5*SS11(ix,il)	  Enddo	  Do ik=1,Nk          tup(ik)=C0	      tus(ik)=C0	  Enddo	  Do 99992 m=1,5	  Do ik=1,Nk	    sigP(ik)=C0	   Enddo          j=1	  Do ix=1,Nx	    sigP(j)=SY(ix,m)	    j=j+jskip	  Enddo	  signi=-1.0	  call FFT(sigP,Nk,signi) !x->k	  Do ik=1,Nk	            tup(ik)=tup(ik)+PC(ik,m,il)*sigP(ik)	  Enddo99992   Continue			  Do 99993 m=6,9	  Do ik=1,Nk	    sigS(ik)=C0	  Enddo          j=1	  Do ix=1,Nx	    sigS(j)=SY(ix,m)	    j=j+jskip	  Enddo	  signi=-1.0	  call FFT(sigS,Nk,signi) !x->k	  Do ik=1,Nk	              tus(ik)=tus(ik)+PC(ik,m,il)*sigS(ik)	  Enddo99993    Continue	  	  return	  end